// ============================================================
// yesanfarm1 GitHub Push Script
// 1) 아래 YOUR_PAT_HERE 를 본인 PAT 로 교체하세요
// 2) F12 콘솔에 전체 붙여넣기 후 Enter
// ============================================================
(async () => {
  const TOKEN = "YOUR_PAT_HERE";
  const REPO  = "ynyntest1/yesanfarm1";
  const BRANCH = "main";
  const BASE   = `https://api.github.com/repos/${REPO}/contents`;

  const files = [
  { path: "views/meal_allowance.py", content: "" },
  { path: "views/team_settings.py", content: "" },
  { path: "requirements.txt", content: "c3RyZWFtbGl0Pj0xLjMxLjAKcGFuZGFzCm9wZW5weXhsCnhsc3h3cml0ZXIKeGxyZApyZXF1ZXN0cwo=" },
  { path: "components/member_sorter/index.html", content: "" }
  ];

  for (const file of files) {
    const url = `${BASE}/${file.path}`;
    const getRes = await fetch(url + `?ref=${BRANCH}`, {
      headers: { Authorization: `token ${TOKEN}`, Accept: "application/vnd.github.v3+json" }
    });
    const existing = getRes.ok ? await getRes.json() : null;

    const putBody = {
      message: `자동 업데이트: ${file.path}`,
      content: file.content,
      branch: BRANCH,
    };
    if (existing?.sha) putBody.sha = existing.sha;

    const putRes = await fetch(url, {
      method: "PUT",
      headers: {
        Authorization: `token ${TOKEN}`,
        Accept: "application/vnd.github.v3+json",
        "Content-Type": "application/json"
      },
      body: JSON.stringify(putBody)
    });

    const result = await putRes.json();
    if (putRes.ok) {
      console.log(`✅ 업로드 성공: ${file.path}`);
    } else {
      console.error(`❌ 실패: ${file.path}`, result.message);
    }
  }
  console.log("🎉 모든 파일 처리 완료!");
})();
